            "rules": [
                {
                    "required": true,
                    "message": "Output prefix is required"
                }
            ]
        }
  ],
  "resources": {
    "cpu": 4,
    "memory": "6GB",
    "docker": "quay.io/biocontainers/trim-galore:0.6.7"
